import socket
import struct
import json

class GameServer:
    def __init__(self, host='0.0.0.0', port=9999):
        self.host = host
        self.port = port
        self.players = []
        self.game_state = {}

    def add_player(self, player_id, player_name):
        self.players.append({'id': player_id, 'name': player_name})
    
    def update_game_state(self, state):
        self.game_state = state

    def handle_request(self, data, address, sock):
        message = data.decode('utf-8')
        if message == "status":
            response = {
                "players": self.players,
                "game_state": self.game_state
            }
            response_data = json.dumps(response).encode('utf-8')
            # Ensure sending large responses without fragmentation
            for i in range(0, len(response_data), 1024):
                sock.sendto(response_data[i:i+1024], address)

    def run(self):
        with socket.socket(socket.AF_INET, socket.SOCK_DGRAM) as sock:
            sock.bind((self.host, self.port))
            print(f"Game server running on {self.host}:{self.port}")

            while True:
                data, address = sock.recvfrom(4096)
                self.handle_request(data, address, sock)

# Example setup
game_server = GameServer()
game_server.add_player(1, "Alice")
game_server.add_player(2, "Bob")
